+    Arena A;
+    PY_BEGIN
+    #define ARGS(_) _(py::handle, tensor) _(py::handle, py_levels) _(int, has_device)
+    MPY_PARSE_ARGS_KWNAMES("OOp", ARGS)
+    #undef ARGS
+
+    if (!THPVariable_Check(tensor.ptr())) {
+        py::raise_error(PyExc_ValueError, "_tensor is not a Tensor?");
+    }
